import{_ as n,c as i,o as s,a1 as a}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Fähigkeiten verwalten: Verfügbare Fähigkeiten abfragen | opencode-agent-skills","description":"Lernen Sie die Verwendung des Tools get_available_skills. Durch Such-, Namespace- und Filterfunktionen finden Sie schnell Fähigkeiten und beherrschen die Kernfunktionen der Fähigkeitenentdeckung und -verwaltung.","frontmatter":{"title":"Fähigkeiten verwalten: Verfügbare Fähigkeiten abfragen | opencode-agent-skills","sidebarTitle":"Fähigkeiten schnell finden","subtitle":"Fähigkeiten verwalten: Verfügbare Fähigkeiten abfragen","description":"Lernen Sie die Verwendung des Tools get_available_skills. Durch Such-, Namespace- und Filterfunktionen finden Sie schnell Fähigkeiten und beherrschen die Kernfunktionen der Fähigkeitenentdeckung und -verwaltung.","tags":["Fähigkeitenverwaltung","Tool-Nutzung","Namensräume"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"de/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"de/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),t={name:"de/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function l(r,e,c,o,h,d){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="verfugbare-fahigkeiten-abfragen-und-auflisten" tabindex="-1">Verfügbare Fähigkeiten abfragen und auflisten <a class="header-anchor" href="#verfugbare-fahigkeiten-abfragen-und-auflisten" aria-label="Permalink to &quot;Verfügbare Fähigkeiten abfragen und auflisten&quot;">​</a></h1><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><ul><li>Mit dem Tool <code>get_available_skills</code> alle verfügbaren Fähigkeiten auflisten</li><li>Bestimmte Fähigkeiten durch Suchanfragen filtern</li><li>Fähigkeiten mit Namensräumen (z. B. <code>project:skill-name</code>) präzise lokalisieren</li><li>Fähigkeitsquellen und ausführbare Skriptlisten erkennen</li></ul><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Sie möchten eine bestimmte Fähigkeit verwenden, können sich aber nicht mehr an den genauuen Namen erinnern. Vielleicht wissen Sie, dass es sich um eine Fähigkeit im Projekt handelt, aber nicht unter welchem Entdeckungspfad. Oder Sie möchten einfach nur schnell sehen, welche Fähigkeiten im aktuellen Projekt verfügbar sind.</p><h2 id="wann-sie-diese-technik-anwenden" tabindex="-1">Wann Sie diese Technik anwenden <a class="header-anchor" href="#wann-sie-diese-technik-anwenden" aria-label="Permalink to &quot;Wann Sie diese Technik anwenden&quot;">​</a></h2><ul><li><strong>Neue Projekte erkunden</strong>: Wenn Sie einem neuen Projekt beitreten, schnell sehen, welche Fähigkeiten verfügbar sind</li><li><strong>Unsicherer Fähigkeitsname</strong>: Sie erinnern sich nur an einen Teil des Namens oder der Beschreibung und benötigen eine Fuzzy-Suche</li><li><strong>Namensraumkonflikte</strong>: Wenn es projekt- und benutzerspezifische Fähigkeiten mit demselben Namen gibt, müssen Sie明确指定使用哪个</li><li><strong>Skripte finden</strong>: Wissen möchten, welche ausführbaren Automatisierungsskripte im Fähigkeitenverzeichnis vorhanden sind</li></ul><h2 id="grundlegende-vorgehensweise" tabindex="-1">Grundlegende Vorgehensweise <a class="header-anchor" href="#grundlegende-vorgehensweise" aria-label="Permalink to &quot;Grundlegende Vorgehensweise&quot;">​</a></h2><p>Das Tool <code>get_available_skills</code> zeigt alle Fähigkeiten an, die in der aktuellen Sitzung verfügbar sind. Das Plugin scannt automatisch Fähigkeiten aus 6 Entdeckungspfaden:</p><div class="info custom-block"><p class="custom-block-title">Fähigkeitsentdeckungspriorität</p><ol><li><code>.opencode/skills/</code> (projektspezifisch OpenCode)</li><li><code>.claude/skills/</code> (projektspezifisch Claude)</li><li><code>~/.config/opencode/skills/</code> (benutzerspezifisch OpenCode)</li><li><code>~/.claude/skills/</code> (benutzerspezifisch Claude)</li><li><code>~/.claude/plugins/cache/</code> (Plugin-Cache)</li><li><code>~/.claude/plugins/marketplaces/</code> (installierte Plugins)</li></ol></div><p>Fähigkeiten mit demselben Namen werden nur nach Priorität behalten, alle weiteren werden ignoriert.</p><p>Die vom Tool zurückgegebenen Informationen umfassen:</p><ul><li><strong>Fähigkeitsname</strong></li><li><strong>Quelletikett</strong> (project, user, claude-project usw.)</li><li><strong>Beschreibung</strong></li><li><strong>Liste ausführbarer Skripte</strong> (falls vorhanden)</li></ul><div class="tip custom-block"><p class="custom-block-title">Namensraumsyntax</p><p>Sie können mit dem Format <code>namespace:skill-name</code>明确指定来源：</p><ul><li><code>project:my-skill</code> - Projektspezifische OpenCode-Fähigkeit verwenden (<code>.opencode/skills/</code>)</li><li><code>claude-project:my-skill</code> - Projektspezifische Claude-Fähigkeit verwenden (<code>.claude/skills/</code>)</li><li><code>user:my-skill</code> - Benutzerspezifische OpenCode-Fähigkeit verwenden (<code>~/.config/opencode/skills/</code>)</li><li><code>claude-user:my-skill</code> - Benutzerspezifische Claude-Fähigkeit verwenden (<code>~/.claude/skills/</code>)</li><li><code>claude-plugins:my-skill</code> - Fähigkeit aus Claude-Plugins verwenden</li></ul></div><h2 id="praktische-anleitung" tabindex="-1">Praktische Anleitung <a class="header-anchor" href="#praktische-anleitung" aria-label="Permalink to &quot;Praktische Anleitung&quot;">​</a></h2><h3 id="schritt-1-alle-verfugbaren-fahigkeiten-auflisten" tabindex="-1">Schritt 1: Alle verfügbaren Fähigkeiten auflisten <a class="header-anchor" href="#schritt-1-alle-verfugbaren-fahigkeiten-auflisten" aria-label="Permalink to &quot;Schritt 1: Alle verfügbaren Fähigkeiten auflisten&quot;">​</a></h3><p>Fordern Sie den KI-Assistenten direkt auf, die Fähigkeiten aufzulisten:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzereingabe:</span></span>
<span class="line"><span>Alle verfügbaren Fähigkeiten auflisten</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Systemantwort:</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Git-Operationen und Zweigverwassistent [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Unit-Tests und Abdeckungsanalyse-Tool</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker-Containerisierung und Deployment-Leitfaden [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  Vollständiger Softwareentwicklungs-Workflow</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Eine Fähigkeitsliste, die für jede Fähigkeit den Namen, das Quelletikett, die Beschreibung und die Skriptliste anzeigt.</p><h3 id="schritt-2-suchanfragen-zum-filtern-verwenden" tabindex="-1">Schritt 2: Suchanfragen zum Filtern verwenden <a class="header-anchor" href="#schritt-2-suchanfragen-zum-filtern-verwenden" aria-label="Permalink to &quot;Schritt 2: Suchanfragen zum Filtern verwenden&quot;">​</a></h3><p>Wenn Sie sich nur noch an einen Teil des Fähigkeitsnamens erinnern:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzereingabe:</span></span>
<span class="line"><span>Fähigkeiten suchen, die &quot;docker&quot; enthalten</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Systemantwort:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker-Containerisierung und Deployment-Leitfaden [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Die Suche stimmt Schlüsselwörter im Fähigkeitsnamen und in der Beschreibung überein und unterstützt <code>*</code> Wildcards:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzereingabe:</span></span>
<span class="line"><span>Fähigkeiten suchen, die mit &quot;test&quot; beginnen</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Systemantwort:</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Unit-Tests und Abdeckungsanalyse-Tool</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Nur Fähigkeiten, die mit den Suchkriterien übereinstimmen.</p><h3 id="schritt-3-fuzzy-match-vorschlage-testen" tabindex="-1">Schritt 3: Fuzzy-Match-Vorschläge testen <a class="header-anchor" href="#schritt-3-fuzzy-match-vorschlage-testen" aria-label="Permalink to &quot;Schritt 3: Fuzzy-Match-Vorschläge testen&quot;">​</a></h3><p>Wenn Sie einen falschen Fähigkeitsnamen eingeben:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzereingabe:</span></span>
<span class="line"><span>Ich möchte docker-asistant verwenden</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Systemantwort:</span></span>
<span class="line"><span>No skills found matching &quot;docker-asistant&quot;. Did you mean &quot;docker-helper&quot;?</span></span></code></pre></div><p>Das Plugin berechnet die Ähnlichkeit automatisch basierend auf der Levenshtein-Distanz und schlägt den ähnlichsten Fähigkeitsnamen vor.</p><p><strong>Was Sie sehen sollten</strong>: Eine Fehlermeldung und den richtigen Fähigkeitsvorschlag.</p><h3 id="schritt-4-namensraume-zur-prazisen-lokalisierung-verwenden" tabindex="-1">Schritt 4: Namensräume zur präzisen Lokalisierung verwenden <a class="header-anchor" href="#schritt-4-namensraume-zur-prazisen-lokalisierung-verwenden" aria-label="Permalink to &quot;Schritt 4: Namensräume zur präzisen Lokalisierung verwenden&quot;">​</a></h3><p>Angenommen, es gibt projekt- und benutzerspezifische Fähigkeiten namens <code>build-helper</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzereingabe:</span></span>
<span class="line"><span>Details von build-helper auflisten</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Systemantwort:</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  Projektspezifische Build-Konfiguration und Compiler-Optimierung [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>Wenn der Benutzer die benutzerspezifische Fähigkeit möchte:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzereingabe:</span></span>
<span class="line"><span>user:build-helper verwenden</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Systemantwort:</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  Generische Build-Toolchain und CI-Konfiguration [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Mit Namensraum-Präfixen können Sie auf Fähigkeiten mit demselben Namen aus verschiedenen Quellen zugreifen.</p><h3 id="schritt-5-ausfuhrbare-skripte-prufen" tabindex="-1">Schritt 5: Ausführbare Skripte prüfen <a class="header-anchor" href="#schritt-5-ausfuhrbare-skripte-prufen" aria-label="Permalink to &quot;Schritt 5: Ausführbare Skripte prüfen&quot;">​</a></h3><p>Sehen Sie, welche Skripte im Fähigkeitenverzeichnis vorhanden sind:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Benutzereingabe:</span></span>
<span class="line"><span>Welche Skripte hat docker-helper?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Systemantwort:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker-Containerisierung und Deployment-Leitfaden [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Die Skripte werden in eckigen Klammern nach den Fähigkeitsinformationen angezeigt, durch Kommas getrennt. Sie können das Tool <code>run_skill_script</code> verwenden, um diese Skripte auszuführen.</p><p><strong>Was Sie sehen sollten</strong>: Den Fähigkeitsnamen gefolgt von einer Liste im Format <code>[scripts: SkriptPfad1, SkriptPfad2, ...]</code>.</p><h2 id="checkliste-✅" tabindex="-1">Checkliste ✅ <a class="header-anchor" href="#checkliste-✅" aria-label="Permalink to &quot;Checkliste ✅&quot;">​</a></h2><ul><li>[ ] Können Sie alle verfügbaren Fähigkeiten auflisten?</li><li>[ ] Können Sie bestimmte Fähigkeiten durch Suchanfragen filtern?</li><li>[ ] Verstehen Sie die Bedeutung der Fähigkeitsquelletiketten (project, user, claude-project usw.)?</li><li>[ ] Können Sie den Zweck und die Syntax von Fähigkeitsnamensräumen erklären?</li><li>[ ] Können Sie aus den Fähigkeitsinformationen die Liste der ausführbaren Skripte identifizieren?</li></ul><h2 id="fallstricke" tabindex="-1">Fallstricke <a class="header-anchor" href="#fallstricke" aria-label="Permalink to &quot;Fallstricke&quot;">​</a></h2><h3 id="fallstrick-1-uberschreibung-von-fahigkeiten-mit-demselben-namen" tabindex="-1">Fallstrick 1: Überschreibung von Fähigkeiten mit demselben Namen <a class="header-anchor" href="#fallstrick-1-uberschreibung-von-fahigkeiten-mit-demselben-namen" aria-label="Permalink to &quot;Fallstrick 1: Überschreibung von Fähigkeiten mit demselben Namen&quot;">​</a></h3><p>Wenn es projekt- und benutzerspezifische Fähigkeiten mit demselben Namen gibt, sind Sie möglicherweise verwirrt, warum nicht die erwartete Fähigkeit geladen wird.</p><p><strong>Grund</strong>: Fähigkeiten werden nach Priorität entdeckt, projekt-spezifisch hat Vorrang vor benutzerspezifisch, und bei demselben Namen wird nur die erste behalten.</p><p><strong>Lösung</strong>: Verwenden Sie Namensräume明确指定，例如 <code>user:my-skill</code> statt <code>my-skill</code>.</p><h3 id="fallstrick-2-suche-unterscheidet-groß-kleinschreibung" tabindex="-1">Fallstrick 2: Suche unterscheidet Groß-/Kleinschreibung <a class="header-anchor" href="#fallstrick-2-suche-unterscheidet-groß-kleinschreibung" aria-label="Permalink to &quot;Fallstrick 2: Suche unterscheidet Groß-/Kleinschreibung&quot;">​</a></h3><p>Suchanfragen verwenden reguläre Ausdrücke, aber mit dem <code>i</code>-Flag, daher wird die Groß-/Kleinschreibung nicht berücksichtigt.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Diese Suchen sind gleichwertig</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="fallstrick-3-escape-zeichen-fur-wildcards" tabindex="-1">Fallstrick 3: Escape-Zeichen für Wildcards <a class="header-anchor" href="#fallstrick-3-escape-zeichen-fur-wildcards" aria-label="Permalink to &quot;Fallstrick 3: Escape-Zeichen für Wildcards&quot;">​</a></h3><p>Das <code>*</code> in der Suche wird automatisch in <code>.*</code> reguläre Ausdrücke konvertiert, Sie müssen nicht manuell escapen:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Fähigkeiten suchen, die mit &quot;test&quot; beginnen</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Entspricht dem regulären Ausdruck /test.*/i</span></span></code></pre></div><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p><code>get_available_skills</code> ist ein Werkzeug zum Erkunden des Fähigkeiten-Ökosystems, das unterstützt:</p><ul><li><strong>Alle Fähigkeiten auflisten</strong>: Ohne Parameter aufrufen</li><li><strong>Suchfilterung</strong>: Durch den <code>query</code>-Parameter Namen und Beschreibung abgleichen</li><li><strong>Namensräume</strong>: Mit <code>namespace:skill-name</code> präzise lokalisieren</li><li><strong>Fuzzy-Match-Vorschläge</strong>: Bei Rechtschreibfehlern automatisch den richtigen Namen vorschlagen</li><li><strong>Skriptlisten</strong>: Ausführbare Automatisierungsskripte anzeigen</li></ul><p>Das Plugin injiziert die Fähigkeitenliste automatisch zu Beginn der Sitzung, daher müssen Sie dieses Tool normalerweise nicht manuell aufrufen. Aber in folgenden Szenarien ist es nützlich:</p><ul><li>Schnell verfügbare Fähigkeiten durchsuchen möchten</li><li>Sich nicht mehr an den genauen Fähigkeitsnamen erinnern</li><li>Fähigkeiten mit demselben Namen aus verschiedenen Quellen unterscheiden müssen</li><li>Die Skriptliste einer bestimmten Fähigkeit sehen möchten</li></ul><h2 id="nachste-lektion" tabindex="-1">Nächste Lektion <a class="header-anchor" href="#nachste-lektion" aria-label="Permalink to &quot;Nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../loading-skills-into-context/">Fähigkeiten in den Sitzungskontext laden</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Das Tool use_skill verwenden, um Fähigkeiten in die aktuelle Sitzung zu laden</li><li>Verstehen, wie Fähigkeitsinhalte im XML-Format in den Kontext injiziert werden</li><li>Den Synthetic Message Injection-Mechanismus beherrschen (synthetic message injection)</li><li>Erfahren, wie Fähigkeiten nach der Sitzungskomprimierung verfügbar bleiben</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken zum Aufklappen der Quellcode-Position</strong></summary><blockquote><p>Letzte Aktualisierung：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummern</th></tr></thead><tbody><tr><td>GetAvailableSkills Tool-Definition</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>discoverAllSkills Funktion</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>resolveSkill Funktion</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>findClosestMatch Funktion</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>Wichtige Typen</strong>：</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>：Aufzählung der Fähigkeitsquelletiketten</li></ul><p><strong>Wichtige Konstanten</strong>：</p><ul><li>Fuzzy-Match-Schwellenwert：<code>0.4</code> (<code>utils.ts:124</code>) - Ähnlichkeiten unter diesem Wert geben keine Vorschläge zurück</li></ul><p><strong>Wichtige Funktionen</strong>：</p><ul><li><code>GetAvailableSkills()</code>：Gibt eine formatierte Fähigkeitsliste zurück, unterstützt Suchfilterung und Fuzzy-Match-Vorschläge</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>：Unterstützt Fähigkeitsauflösung im Format <code>namespace:skill-name</code></li><li><code>findClosestMatch(input: string, candidates: string[])</code>：Berechnet die beste Übereinstimmung basierend auf verschiedenen Matching-Strategien (Präfix, Enthaltensein, Bearbeitungsdistanz)</li></ul><p><strong>Geschäftsregeln</strong>：</p><ul><li>Fähigkeiten mit demselben Namen werden nach Entdeckungsreihenfolge dedupliziert, nur die erste wird behalten (<code>skills.ts:258</code>)</li><li>Suchanfragen unterstützen das Wildcard-Zeichen <code>*</code>, das automatisch in reguläre Ausdrücke konvertiert wird (<code>tools.ts:43</code>)</li><li>Fuzzy-Match-Vorschläge werden nur ausgelöst, wenn ein Suchparameter vorhanden ist und keine Ergebnisse gefunden wurden (<code>tools.ts:49-57</code>)</li></ul></details>`,64)])])}const g=n(t,[["render",l]]);export{p as __pageData,g as default};
